USE P21;
SET NOCOUNT ON;
SET TRANSACTION ISOLATION LEVEL READ UNCOMMITTED;
DECLARE @Target int=682, @Good int=681;
DROP TABLE IF EXISTS #scope;
CREATE TABLE #scope(sample_name varchar(20), crh_uid int);
INSERT #scope VALUES('TARGET',@Target),('KNOWN_GOOD',@Good);
SELECT result_set='document_line_bin_summary', s.sample_name, document_no=CONVERT(varchar(50),s.crh_uid), dlb_count=CONVERT(varchar(50),COUNT(dlb.document_line_bin_uid)), line_count=CONVERT(varchar(50),COUNT(DISTINCT dlb.line_no)), bin_count=CONVERT(varchar(50),COUNT(DISTINCT dlb.bin_cd)), unit_quantity=CONVERT(varchar(50),SUM(COALESCE(dlb.unit_quantity,0))), qty_to_change=CONVERT(varchar(50),SUM(COALESCE(dlb.qty_to_change,0))), qty_applied=CONVERT(varchar(50),SUM(COALESCE(dlb.qty_applied,0)))
FROM #scope s LEFT JOIN dbo.document_line_bin dlb ON dlb.document_type='CR' AND dlb.document_no=s.crh_uid
GROUP BY s.sample_name,s.crh_uid
ORDER BY s.sample_name DESC;
SELECT result_set='container_line_vs_bin', s.sample_name, crl.container_receipts_hdr_uid, crl.container_receipts_line_uid, vrl.line_no, item_id=im.item_id, crl_qty=CONVERT(varchar(50),crl.qty_received), dlb_rows=CONVERT(varchar(50),COUNT(dlb.document_line_bin_uid)), dlb_unit_qty=CONVERT(varchar(50),SUM(COALESCE(dlb.unit_quantity,0))), bins=STRING_AGG(CONVERT(varchar(max),dlb.bin_cd), ',')
FROM #scope s
JOIN dbo.container_receipts_line crl ON crl.container_receipts_hdr_uid=s.crh_uid
JOIN dbo.vessel_receipts_line vrl ON vrl.vessel_receipts_line_uid=crl.vessel_receipts_line_uid
JOIN dbo.po_line pol ON pol.po_line_uid=vrl.po_line_uid
JOIN dbo.inv_mast im ON im.inv_mast_uid=pol.inv_mast_uid
LEFT JOIN dbo.document_line_bin dlb ON dlb.document_type='CR' AND dlb.document_no=crl.container_receipts_hdr_uid AND dlb.line_no=vrl.line_no
GROUP BY s.sample_name, crl.container_receipts_hdr_uid, crl.container_receipts_line_uid, vrl.line_no, im.item_id, crl.qty_received
ORDER BY s.sample_name DESC, CASE WHEN COUNT(dlb.document_line_bin_uid)=0 THEN 0 ELSE 1 END, vrl.line_no;
SELECT result_set='document_line_bin_columns', column_id=CONVERT(varchar(20), c.column_id), column_name=c.name, type_name=ty.name
FROM sys.columns c JOIN sys.types ty ON ty.user_type_id=c.user_type_id WHERE c.object_id=OBJECT_ID('dbo.document_line_bin') ORDER BY c.column_id;
